1	// Quorum review (multi-model review) end-to-end UI flow.
2	//
3	// Driving spec for the quorum-review UI surfaced from
4	// `ddx agent run --quorum=majority --harnesses=a,b,c`. The flow under test:
5	//
6	//   1. Operator opens a bead (or artifact) and dispatches a quorum review,
7	//      picking ≥2 harnesses and a verdict policy (majority / unanimous).
8	//   2. Server fans out to each harness and streams per-model findings.
9	//   3. UI shows a per-arm column with verdict + structured findings, plus a
10	//      rollup verdict computed from the policy.
11	//   4. Operator can drill into a single arm's raw output and link back to the
12	//      originating bead / artifact.
13	//
14	// The quorum-review view is not yet implemented (PRD §437 "Multi-agent review
15	// workflow produces structured findings from quorum"). These tests are checked
16	// in as a TDD seed: every case is marked `test.fixme` so CI stays green; once
17	// the view ships, drop the fixme markers one case at a time as features land.
18	// Mocks below describe the GraphQL contract the view is expected to consume.
19	
20	import { expect, test, type Page } from '@playwright/test';
21	
22	const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
23	const PROJECT_ID = 'proj-1';
24	const PROJECTS = [{ id: PROJECT_ID, name: 'Project Alpha', path: '/repos/alpha' }];
25	const BEAD_ID = 'ddx-quorum-001';
26	
27	const REVIEW_BASE_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads/${BEAD_ID}/reviews/quorum`;
28	
29	const HARNESSES = [
30		{ name: 'claude', provider: 'anthropic', model: 'claude-opus-4-7' },
31		{ name: 'codex', provider: 'openai', model: 'gpt-5.4' },
32		{ name: 'gemini', provider: 'google', model: 'gemini-2.5-pro' }
33	];
34	
35	const REVIEW_ID = 'qrv-001';
36	
37	const QUORUM_REVIEW = {
38		id: REVIEW_ID,
39		beadId: BEAD_ID,
40		policy: 'majority',
41		state: 'completed',
42		rollupVerdict: 'PASS',
43		createdAt: '2026-05-01T07:00:00Z',
44		completedAt: '2026-05-01T07:04:13Z',
45		arms: [
46			{
47				harness: 'claude',
48				provider: 'anthropic',
49				model: 'claude-opus-4-7',
50				verdict: 'PASS',
51				summary: 'Acceptance criteria satisfied; no blocking issues.',
52				findings: [
53					{ severity: 'info', message: 'Consider extracting the retry helper.' }
54				],
55				rawOutputUrl: `/api/quorum-reviews/${REVIEW_ID}/arms/claude/raw`
56			},
57			{
58				harness: 'codex',
59				provider: 'openai',
60				model: 'gpt-5.4',
61				verdict: 'PASS',
62				summary: 'Looks good. One nit on naming.',
63				findings: [
64					{ severity: 'nit', message: 'Rename `tmp` to `pendingMerge` for clarity.' }
65				],
66				rawOutputUrl: `/api/quorum-reviews/${REVIEW_ID}/arms/codex/raw`
67			},
68			{
69				harness: 'gemini',
70				provider: 'google',
71				model: 'gemini-2.5-pro',
72				verdict: 'BLOCK',
73				summary: 'Found a missing nil-check on the merge path.',
74				findings: [
75					{
76						severity: 'blocking',
77						message: 'cli/internal/agent/merge.go:142 dereferences result without nil-check.'
78					}
79				],
80				rawOutputUrl: `/api/quorum-reviews/${REVIEW_ID}/arms/gemini/raw`
81			}
82		]
83	};
84	
85	async function mockQuorumReview(
86		page: Page,
87		opts: {
88			dispatchFn?: (req: Record<string, unknown>) => Record<string, unknown>;
89			review?: typeof QUORUM_REVIEW;
90		} = {}
91	) {
92		await page.route('/graphql', async (route) => {
93			const body = route.request().postDataJSON() as {
94				query: string;
95				variables?: Record<string, unknown>;
96			};
97	
98			if (body.query.includes('NodeInfo')) {
99				await route.fulfill({
100					status: 200,
101					contentType: 'application/json',
102					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
103				});
104				return;
105			}
106			if (body.query.includes('Projects')) {
107				await route.fulfill({
108					status: 200,
109					contentType: 'application/json',
110					body: JSON.stringify({
111						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
112					})
113				});
114				return;
115			}
116			if (body.query.includes('Harnesses') || body.query.includes('harnesses')) {
117				await route.fulfill({
118					status: 200,
119					contentType: 'application/json',
120					body: JSON.stringify({ data: { harnesses: HARNESSES } })
121				});
122				return;
123			}
124			if (body.query.includes('QuorumReview') || body.query.includes('quorumReview')) {
125				await route.fulfill({
126					status: 200,
127					contentType: 'application/json',
128					body: JSON.stringify({ data: { quorumReview: opts.review ?? QUORUM_REVIEW } })
129				});
130				return;
131			}
132			if (
133				body.query.includes('QuorumReviewDispatch') ||
134				body.query.includes('quorumReviewDispatch')
135			) {
136				const result = opts.dispatchFn
137					? opts.dispatchFn(body.variables ?? {})
138					: { id: REVIEW_ID, state: 'queued' };
139				await route.fulfill({
140					status: 200,
141					contentType: 'application/json',
142					body: JSON.stringify({ data: { quorumReviewDispatch: result } })
143				});
144				return;
145			}
146			await route.continue();
147		});
148	}
149	
150	test.describe('quorum review UI', () => {
151		test('dispatch: bead page lets operator pick harnesses and verdict policy', async ({
152			page
153		}) => {
154			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
155	
156			let dispatched: Record<string, unknown> | null = null;
157			await mockQuorumReview(page, {
158				dispatchFn: (req) => {
159					dispatched = req;
160					return { id: REVIEW_ID, state: 'queued', armCount: 2 };
161				}
162			});
163	
164			await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads/${BEAD_ID}`);
165	
166			await page.getByRole('button', { name: /quorum review/i }).click();
167	
168			const dialog = page.getByRole('dialog', { name: /quorum review/i });
169			await expect(dialog).toBeVisible();
170	
171			// Harness checkboxes pre-populated from /graphql harnesses query.
172			await dialog.getByRole('checkbox', { name: /claude/i }).check();
173			await dialog.getByRole('checkbox', { name: /codex/i }).check();
174	
175			// Policy selector defaults to majority.
176			const policy = dialog.getByRole('combobox', { name: /policy|verdict/i });
177			await expect(policy).toHaveValue('majority');
178			await policy.selectOption('unanimous');
179	
180			await dialog.getByRole('button', { name: /start|dispatch/i }).click();
181	
182			await expect.poll(() => dispatched).not.toBeNull();
183			expect(dispatched).toMatchObject({
184				beadId: BEAD_ID,
185				policy: 'unanimous',
186				harnesses: expect.arrayContaining(['claude', 'codex'])
187			});
188	
189			// Operator is taken to the review detail page on dispatch.
190			await expect(page).toHaveURL(new RegExp(`/reviews/quorum/${REVIEW_ID}$`));
191		});
192	
193		test('view: per-arm columns render verdicts, summaries, and findings', async ({ page }) => {
194			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
195	
196			await mockQuorumReview(page);
197			await page.goto(`${REVIEW_BASE_URL}/${REVIEW_ID}`);
198	
199			// Three arm columns, one per harness.
200			const arms = page.getByTestId('quorum-arm');
201			await expect(arms).toHaveCount(3);
202	
203			for (const arm of QUORUM_REVIEW.arms) {
204				const col = page.getByTestId(`quorum-arm-${arm.harness}`);
205				await expect(col).toBeVisible();
206				await expect(col).toContainText(arm.model);
207				await expect(col.getByTestId('arm-verdict')).toContainText(arm.verdict);
208				await expect(col).toContainText(arm.summary);
209				for (const finding of arm.findings) {
210					await expect(col).toContainText(finding.message);
211				}
212			}
213		});
214	
215		test('rollup: majority policy produces PASS when 2/3 arms pass', async ({ page }) => {
216			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
217	
218			await mockQuorumReview(page);
219			await page.goto(`${REVIEW_BASE_URL}/${REVIEW_ID}`);
220	
221			const rollup = page.getByTestId('quorum-rollup-verdict');
222			await expect(rollup).toBeVisible();
223			await expect(rollup).toContainText(/PASS/);
224			await expect(rollup).toContainText(/majority/i);
225			await expect(rollup).toContainText(/2\s*\/\s*3/);
226		});
227	
228		test('rollup: unanimous policy with one BLOCK arm produces BLOCK', async ({ page }) => {
229			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
230	
231			await mockQuorumReview(page, {
232				review: { ...QUORUM_REVIEW, policy: 'unanimous', rollupVerdict: 'BLOCK' }
233			});
234			await page.goto(`${REVIEW_BASE_URL}/${REVIEW_ID}`);
235	
236			const rollup = page.getByTestId('quorum-rollup-verdict');
237			await expect(rollup).toContainText(/BLOCK/);
238			await expect(rollup).toContainText(/unanimous/i);
239		});
240	
241		test('drill-in: arm column links to raw output and back to bead', async ({ page }) => {
242			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
243	
244			await mockQuorumReview(page);
245			await page.goto(`${REVIEW_BASE_URL}/${REVIEW_ID}`);
246	
247			const geminiCol = page.getByTestId('quorum-arm-gemini');
248			const rawLink = geminiCol.getByRole('link', { name: /raw output/i });
249			await expect(rawLink).toHaveAttribute(
250				'href',
251				`/api/quorum-reviews/${REVIEW_ID}/arms/gemini/raw`
252			);
253	
254			await page.getByRole('link', { name: new RegExp(BEAD_ID) }).click();
255			await expect(page).toHaveURL(
256				new RegExp(`/projects/${PROJECT_ID}/beads/${BEAD_ID}$`)
257			);
258		});
259	
260		test('streaming: in-flight review shows pending arms before completion', async ({ page }) => {
261			test.fixme(true, 'quorum review UI not implemented yet (PRD §437)');
262	
263			const inflight = {
264				...QUORUM_REVIEW,
265				state: 'running',
266				rollupVerdict: null,
267				completedAt: null,
268				arms: [
269					{ ...QUORUM_REVIEW.arms[0] },
270					{
271						harness: 'codex',
272						provider: 'openai',
273						model: 'gpt-5.4',
274						verdict: null,
275						summary: null,
276						findings: [],
277						rawOutputUrl: null
278					},
279					{
280						harness: 'gemini',
281						provider: 'google',
282						model: 'gemini-2.5-pro',
283						verdict: null,
284						summary: null,
285						findings: [],
286						rawOutputUrl: null
287					}
288				]
289			};
290	
291			await mockQuorumReview(page, { review: inflight as typeof QUORUM_REVIEW });
292			await page.goto(`${REVIEW_BASE_URL}/${REVIEW_ID}`);
293	
294			await expect(page.getByTestId('quorum-rollup-verdict')).toContainText(/running|pending/i);
295			await expect(page.getByTestId('quorum-arm-codex').getByTestId('arm-verdict')).toContainText(
296				/pending|running|—/
297			);
298			await expect(page.getByTestId('quorum-arm-claude').getByTestId('arm-verdict')).toContainText(
299				'PASS'
300			);
301		});
302	});
